const { PrismaClient } = require('@prisma/client');
const prisma = new PrismaClient();

async function main() {
  const platforms = [
    { key: 'CHATGPT', displayName: 'ChatGPT' },
    { key: 'PERPLEXITY', displayName: 'Perplexity' },
    { key: 'GEMINI', displayName: 'Gemini' },
    { key: 'AI_OVERVIEW', displayName: 'Google AI Overview', enabled: false },
  ];
  for (const p of platforms) {
    await prisma.platform.upsert({
      where: { key: p.key },
      update: { displayName: p.displayName, enabled: p.enabled ?? true },
      create: p,
    });
  }
  const org = await prisma.organization.upsert({
    where: { stripeCustomerId: 'demo' },
    update: {},
    create: { name: 'Demo Roofing Co', plan: 'PRO', status: 'TRIALING', stripeCustomerId: 'demo' },
  });
  await prisma.business.create({
    data: { organizationId: org.id, name: 'Demo Roofing Co', category: 'roofer',
            city: 'Austin', state: 'TX', website: 'https://example.com' },
  });
  console.log('Seed complete.');
}
main().catch((e) => { console.error(e); process.exit(1); }).finally(() => prisma.$disconnect());

